namespace UniversityCatalog.Models;

public class Department
{
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

namespace UniversityCatalog.Models;

public class Instructor
{
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
}

namespace UniversityCatalog.Models;

public class Schedule
{
    public string Days { get; set; } = "";
    public string Time { get; set; } = "";
    public string Location { get; set; } = "";
    public string Semester { get; set; } = "";
}

namespace UniversityCatalog.Models;

public class Course
{
    public string Id { get; set; } = "";
    public string Title { get; set; } = "";
    public string Code { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Level { get; set; } = "";
    public bool IsFeatured { get; set; }
    public string DepartmentId { get; set; } = "";
    public Instructor Instructor { get; set; } = new();
    public Schedule Schedule { get; set; } = new();
    public List<string> Prerequisites { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 uppercase letters followed by 6 digits (e.g., CS123456).")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    public string CourseId { get; set; } = "";

    [StringLength(500)]
    public string? Comments { get; set; }
}

using UniversityCatalog.Models;

namespace UniversityCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments =
        [
            new Department { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new Department { Id = "math", Name = "Mathematics", Description = "Exploration of abstract structures, quantity, and change." },
            new Department { Id = "phys", Name = "Physics", Description = "Understanding the fundamental laws governing the natural world." }
        ];

        _courses =
        [
            new Course
            {
                Id = "cs101", Code = "CS 101", Title = "Introduction to Computer Science",
                Description = "A broad introduction to computer science covering computational thinking, basic programming in Python, data representation, and an overview of modern computing systems. Suitable for students with no prior programming experience.",
                Credits = 3, Level = "Introductory", IsFeatured = true, DepartmentId = "cs",
                Instructor = new Instructor { Name = "Dr. Alice Chen", Title = "Associate Professor", Bio = "Dr. Chen specializes in computer science education and has published extensively on pedagogy for introductory programming courses.", Email = "achen@university.edu" },
                Schedule = new Schedule { Days = "Mon / Wed / Fri", Time = "9:00 AM – 9:50 AM", Location = "Science Hall 210", Semester = "Fall 2025" }
            },
            new Course
            {
                Id = "cs201", Code = "CS 201", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures including arrays, linked lists, trees, graphs, and hash tables along with algorithm design and analysis techniques.",
                Credits = 4, Level = "Intermediate", IsFeatured = false, DepartmentId = "cs",
                Instructor = new Instructor { Name = "Dr. Robert Nguyen", Title = "Professor", Bio = "Dr. Nguyen's research focuses on algorithm optimization and competitive programming. He has coached the university's ICPC team for over a decade.", Email = "rnguyen@university.edu" },
                Schedule = new Schedule { Days = "Tue / Thu", Time = "10:30 AM – 12:00 PM", Location = "Engineering 305", Semester = "Fall 2025" },
                Prerequisites = ["CS 101"]
            },
            new Course
            {
                Id = "cs310", Code = "CS 310", Title = "Operating Systems",
                Description = "Concepts of modern operating systems including process management, memory management, file systems, and concurrency. Includes hands-on projects in C.",
                Credits = 4, Level = "Advanced", IsFeatured = false, DepartmentId = "cs",
                Instructor = new Instructor { Name = "Dr. Robert Nguyen", Title = "Professor", Bio = "Dr. Nguyen's research focuses on algorithm optimization and competitive programming. He has coached the university's ICPC team for over a decade.", Email = "rnguyen@university.edu" },
                Schedule = new Schedule { Days = "Mon / Wed", Time = "2:00 PM – 3:30 PM", Location = "Engineering 110", Semester = "Fall 2025" },
                Prerequisites = ["CS 201"]
            },
            new Course
            {
                Id = "math101", Code = "MATH 101", Title = "Calculus I",
                Description = "Limits, derivatives, and integrals of single-variable functions with applications to science and engineering. Emphasis on conceptual understanding and problem solving.",
                Credits = 4, Level = "Introductory", IsFeatured = true, DepartmentId = "math",
                Instructor = new Instructor { Name = "Dr. Maria Lopez", Title = "Professor", Bio = "Dr. Lopez is an award-winning educator whose innovative teaching methods have transformed the way calculus is taught at the university.", Email = "mlopez@university.edu" },
                Schedule = new Schedule { Days = "Mon / Tue / Wed / Thu", Time = "8:00 AM – 8:50 AM", Location = "Math Building 101", Semester = "Fall 2025" }
            },
            new Course
            {
                Id = "math201", Code = "MATH 201", Title = "Linear Algebra",
                Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues and eigenvectors with applications to data science and engineering.",
                Credits = 3, Level = "Intermediate", IsFeatured = false, DepartmentId = "math",
                Instructor = new Instructor { Name = "Dr. James Park", Title = "Assistant Professor", Bio = "Dr. Park researches numerical linear algebra and its applications in machine learning. He joined the department in 2022.", Email = "jpark@university.edu" },
                Schedule = new Schedule { Days = "Tue / Thu", Time = "1:00 PM – 2:30 PM", Location = "Math Building 215", Semester = "Fall 2025" },
                Prerequisites = ["MATH 101"]
            },
            new Course
            {
                Id = "math305", Code = "MATH 305", Title = "Probability and Statistics",
                Description = "Introduction to probability theory, random variables, distributions, hypothesis testing, and regression analysis with real-world data sets.",
                Credits = 3, Level = "Intermediate", IsFeatured = false, DepartmentId = "math",
                Instructor = new Instructor { Name = "Dr. Maria Lopez", Title = "Professor", Bio = "Dr. Lopez is an award-winning educator whose innovative teaching methods have transformed the way calculus is taught at the university.", Email = "mlopez@university.edu" },
                Schedule = new Schedule { Days = "Mon / Wed / Fri", Time = "11:00 AM – 11:50 AM", Location = "Math Building 310", Semester = "Fall 2025" },
                Prerequisites = ["MATH 101"]
            },
            new Course
            {
                Id = "phys101", Code = "PHYS 101", Title = "General Physics I: Mechanics",
                Description = "Newtonian mechanics, energy, momentum, rotational dynamics, and gravitation. Includes a weekly laboratory section with hands-on experiments.",
                Credits = 4, Level = "Introductory", IsFeatured = true, DepartmentId = "phys",
                Instructor = new Instructor { Name = "Dr. Elena Rossi", Title = "Associate Professor", Bio = "Dr. Rossi is an experimental physicist whose research in quantum optics has been published in Nature and Physical Review Letters.", Email = "erossi@university.edu" },
                Schedule = new Schedule { Days = "Mon / Wed / Fri", Time = "10:00 AM – 10:50 AM", Location = "Physics Lab 120", Semester = "Fall 2025" }
            },
            new Course
            {
                Id = "phys202", Code = "PHYS 202", Title = "Electromagnetism",
                Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves. Combines rigorous theory with practical laboratory work.",
                Credits = 4, Level = "Intermediate", IsFeatured = false, DepartmentId = "phys",
                Instructor = new Instructor { Name = "Dr. Samuel Okafor", Title = "Professor", Bio = "Dr. Okafor has spent 20 years researching electromagnetic theory and its applications in telecommunications and medical imaging.", Email = "sokafor@university.edu" },
                Schedule = new Schedule { Days = "Tue / Thu", Time = "3:00 PM – 4:30 PM", Location = "Physics Lab 220", Semester = "Fall 2025" },
                Prerequisites = ["PHYS 101", "MATH 101"]
            },
            new Course
            {
                Id = "phys310", Code = "PHYS 310", Title = "Quantum Mechanics",
                Description = "Wave-particle duality, Schrödinger equation, quantum states, measurement theory, and applications to atomic and molecular systems.",
                Credits = 3, Level = "Advanced", IsFeatured = true, DepartmentId = "phys",
                Instructor = new Instructor { Name = "Dr. Elena Rossi", Title = "Associate Professor", Bio = "Dr. Rossi is an experimental physicist whose research in quantum optics has been published in Nature and Physical Review Letters.", Email = "erossi@university.edu" },
                Schedule = new Schedule { Days = "Mon / Wed", Time = "4:00 PM – 5:30 PM", Location = "Physics Lab 305", Semester = "Fall 2025" },
                Prerequisites = ["PHYS 202", "MATH 201"]
            }
        ];
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id.Equals(id, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetCourses(string? search, string? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
            query = query.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));

        return query.ToList();
    }

    public Course? GetCourse(string id) =>
        _courses.FirstOrDefault(c => c.Id.Equals(id, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();
}

