                Schedule = new Schedule { Days = "Tue / Thu", Time = "3:00 PM – 4:30 PM", Location = "Physics Lab 220", Semester = "Fall 2025" },
                Prerequisites = ["PHYS 101", "MATH 101"]
            },
            new Course
            {
                Id = "phys310", Code = "PHYS 310", Title = "Quantum Mechanics",
                Description = "Wave-particle duality, Schrödinger equation, quantum states, measurement theory, and applications to atomic and molecular systems.",
                Credits = 3, Level = "Advanced", IsFeatured = true, DepartmentId = "phys",
                Instructor = new Instructor { Name = "Dr. Elena Rossi", Title = "Associate Professor", Bio = "Dr. Rossi is an experimental physicist whose research in quantum optics has been published in Nature and Physical Review Letters.", Email = "erossi@university.edu" },
                Schedule = new Schedule { Days = "Mon / Wed", Time = "4:00 PM – 5:30 PM", Location = "Physics Lab 305", Semester = "Fall 2025" },
                Prerequisites = ["PHYS 202", "MATH 201"]
            }
        ];
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id.Equals(id, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetCourses(string? search, string? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
            query = query.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));

        return query.ToList();
    }

    public Course? GetCourse(string id) =>
        _courses.FirstOrDefault(c => c.Id.Equals(id, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();
}

