@page "/catalog"
@inject CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<CatalogFilters Departments="departments" Search="@Search" DepartmentId="@DepartmentId" />

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found. Try adjusting your search or filters.</div>
}
else
{
    <p class="text-muted mb-3">Showing @courses.Count course(s)</p>
    <div class="row row-cols-1 row-cols-md-2 g-3">
        @foreach (var course in courses)
        {
            <div class="col">
                <CourseCard Course="course" />
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public string? DepartmentId { get; set; }

    private List<Course> courses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{CourseId}"
@inject CatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course not found.</h1>
    <p>The course you are looking for does not exist.</p>
    <a href="/catalog">Back to Catalog</a>
}
else
{
    <PageTitle>@course.Code — @course.Title</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/catalog">Catalog</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="mb-3">
        <span class="badge bg-primary fs-6">@course.Credits Credits</span>
        <span class="badge bg-secondary fs-6">@course.Level</span>
    </div>

    <p class="lead">@course.Description</p>

    @if (course.Prerequisites.Count > 0)
    {
        <h4>Prerequisites</h4>
        <ul>
            @foreach (var prereq in course.Prerequisites)
            {
                <li>@prereq</li>
            }
        </ul>
    }

    <h4 class="mt-4">Schedule</h4>
    <CourseScheduleTable Schedule="course.Schedule" />

    <h4 class="mt-4">Instructor</h4>
    <InstructorBio Instructor="course.Instructor" />

    <div class="mt-4 d-flex gap-3">
        <a href="/enroll?courseId=@course.Id" class="btn btn-success">Enroll in this Course</a>
        <a href="/catalog" class="btn btn-outline-secondary">Back to Catalog</a>
    </div>
}

@code {
    [Parameter] public string CourseId { get; set; } = "";

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(CourseId);
    }
}

@page "/enroll"
@inject CatalogService CatalogService

<PageTitle>Enroll</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Model!.FullName</strong>. Your enrollment request for
           <strong>@(CatalogService.GetCourse(Model.CourseId)?.Title ?? Model.CourseId)</strong>
           has been received.</p>
        <p>Student ID: @Model.StudentId</p>
        <hr />
        <a href="/catalog" class="btn btn-primary">Back to Catalog</a>
        <a href="/enroll" class="btn btn-outline-secondary ms-2">Submit Another</a>
    </div>
}
else
{
    <EditForm Model="Model" method="post" FormName="enrollment" Enhance OnValidSubmit="HandleSubmit">
        <AntiforgeryToken />
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger mb-3" />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <InputText id="fullName" @bind-Value="Model!.FullName" class="form-control" />
            <ValidationMessage For="() => Model.FullName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model!.StudentId" class="form-control" placeholder="e.g., CS123456" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model!.CourseId" class="form-select">
                <option value="">— Select a course —</option>
                @foreach (var c in allCourses)
                {
                    <option value="@c.Id">@c.Code — @c.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <div class="mb-3">
            <label for="comments" class="form-label">Comments (optional)</label>
            <InputTextArea id="comments" @bind-Value="Model!.Comments" class="form-control" rows="3" />
            <ValidationMessage For="() => Model.Comments" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromQuery] public string? CourseId { get; set; }
    [SupplyParameterFromForm] public EnrollmentRequest? Model { get; set; }

    private List<Course> allCourses = [];
    private bool submitted;

    protected override void OnInitialized()
    {
        allCourses = CatalogService.GetCourses(null, null);
        Model ??= new EnrollmentRequest { CourseId = CourseId ?? "" };
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

