         <a href="/enroll" class="btn btn-outline-secondary ms-2">Submit Another</a>
     </div>
 }
 else
 {
     <EditForm Model="Model" method="post" FormName="enrollment" Enhance OnValidSubmit="HandleSubmit">
         <AntiforgeryToken />
         <DataAnnotationsValidator />
         <ValidationSummary class="text-danger mb-3" />

         <div class="mb-3">
             <label for="fullName" class="form-label">Full Name</label>
             <InputText id="fullName" @bind-Value="Model!.FullName" class="form-control" />
             <ValidationMessage For="() => Model.FullName" />
         </div>

         <div class="mb-3">
             <label for="studentId" class="form-label">Student ID</label>
             <InputText id="studentId" @bind-Value="Model!.StudentId" class="form-control" placeholder="e.g., CS123456" />
             <ValidationMessage For="() => Model.StudentId" />
         </div>

         <div class="mb-3">
             <label for="courseId" class="form-label">Course</label>
             <InputSelect id="courseId" @bind-Value="Model!.CourseId" class="form-select">
                 <option value="">— Select a course —</option>
                 @foreach (var c in allCourses)
                 {
                     <option value="@c.Id">@c.Code — @c.Title</option>
                 }
             </InputSelect>
             <ValidationMessage For="() => Model.CourseId" />
         </div>

         <div class="mb-3">
             <label for="comments" class="form-label">Comments (optional)</label>
             <InputTextArea id="comments" @bind-Value="Model!.Comments" class="form-control" rows="3" />
             <ValidationMessage For="() => Model.Comments" />
         </div>

         <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
     </EditForm>
 }

 @code {
     [SupplyParameterFromQuery] public string? CourseId { get; set; }
     [SupplyParameterFromForm] public EnrollmentRequest? Model { get; set; }

     private List<Course> allCourses = [];
     private bool submitted;

     protected override void OnInitialized()
     {
         allCourses = CatalogService.GetCourses(null, null);
         Model ??= new EnrollmentRequest { CourseId = CourseId ?? "" };
     }

     private void HandleSubmit()
     {
         submitted = true;
     }
 }

